mapper.select:
SELECT id, type_id, label, value, color, sort_order, status, create_time, update_time
FROM sys_dict_item
WHERE id = #{id}

SELECT id, type_id, label, value, color, sort_order, status, create_time, update_time
FROM sys_dict_item
WHERE type_id = #{typeId}
  AND value = #{value}

mapper.insert:
INSERT INTO sys_dict_item (
    id, type_id, label, value, color, sort_order, status
) VALUES (
    #{id}, #{typeId}, #{label}, #{value}, #{color}, #{sortOrder}, #{status}
)
